import { useState } from "react";

const BG_IMAGE = "https://www.figma.com/api/mcp/asset/5f79325d-cc27-4d8f-8d8d-6f6d23be63b3";

const s = {
  page: {
    display: "flex", width: "100vw", height: "100vh",
    fontFamily: "'Libre Bodoni', serif", background: "#fff", overflow: "hidden",
  },
  left: {
    width: 654, minHeight: "100vh", flexShrink: 0,
    backgroundImage: `url(${BG_IMAGE})`,
    backgroundSize: "cover", backgroundPosition: "center",
  },
  right: {
    flex: 1, display: "flex", flexDirection: "column",
    padding: "40px 60px", overflowY: "auto",
  },
  title: { fontSize: 64, fontWeight: 400, color: "#5f4a28", marginBottom: 12, lineHeight: 1.1 },
  subtitle: { fontSize: 24, fontWeight: 700, color: "#5f4a28", marginBottom: 6 },
  tagline: { fontSize: 24, fontWeight: 700, color: "rgba(95,74,40,0.5)", marginBottom: 28 },
  label: { fontSize: 20, fontWeight: 700, color: "#5f4a28", marginBottom: 6, display: "block" },
  input: {
    width: "100%", height: 46, borderRadius: 20, border: "none",
    background: "#ecdcc2", padding: "0 16px", fontSize: 18,
    fontFamily: "'Libre Bodoni', serif", color: "#5f4a28",
    outline: "none", marginBottom: 20, boxSizing: "border-box",
  },
  hint: { fontSize: 14, color: "rgba(95,74,40,0.7)", marginTop: -14, marginBottom: 20 },
  createBtn: {
    width: "100%", height: 46, borderRadius: 20, border: "none",
    background: "#ecdcc2", fontFamily: "'Libre Bodoni', serif",
    fontSize: 20, fontWeight: 700, color: "#5f4a28",
    cursor: "pointer", marginTop: 8, marginBottom: 16,
    transition: "background 0.2s",
  },
  loginRow: { fontSize: 24, fontWeight: 700, color: "#5f4a28" },
  loginLink: { textDecoration: "underline", cursor: "pointer" },
};

export default function SignUpPage({ onNavigate }) {
  const [form, setForm] = useState({ name: "", phone: "", email: "", password: "", confirm: "" });
  const set = (k) => (e) => setForm({ ...form, [k]: e.target.value });

  return (
    <div style={s.page}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Libre+Bodoni:wght@400;700&display=swap');`}</style>

      {/* Left — salon photo */}
      <div style={s.left} />

      {/* Right — form */}
      <div style={s.right}>
        {/* Back to website */}
        <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 32, cursor: "pointer" }}
          onClick={() => onNavigate("home")}>
          <span style={{ fontSize: 20, color: "#5f4a28" }}>◀</span>
          <span style={{ fontSize: 20, color: "#5f4a28", fontWeight: 400 }}>Back to website</span>
        </div>

        <h1 style={s.title}>Create your account</h1>
        <p style={s.subtitle}>Join Glow &amp; Shine today</p>
        <p style={s.tagline}>Timeless Beauty, Modern Touch</p>

        <label style={s.label}>Full Name</label>
        <input style={s.input} placeholder="Lara Walker" value={form.name} onChange={set("name")} />

        <label style={s.label}>Phone</label>
        <input style={s.input} placeholder="+40734782335" value={form.phone} onChange={set("phone")} />

        <label style={s.label}>Email</label>
        <input style={s.input} type="email" placeholder="abc123@gmail.com" value={form.email} onChange={set("email")} />

        <label style={s.label}>Password</label>
        <input style={s.input} type="password" placeholder="••••••••" value={form.password} onChange={set("password")} />
        <p style={s.hint}>
          Password must contain at least 8 characters, one uppercase letter, one number and one special character
        </p>

        <label style={s.label}>Confirm Password</label>
        <input style={s.input} type="password" placeholder="••••••••" value={form.confirm} onChange={set("confirm")} />

        <button style={s.createBtn} onClick={() => onNavigate("login")}>
          Create Account
        </button>

        <p style={s.loginRow}>
          Already have an account?{" "}
          <span style={s.loginLink} onClick={() => onNavigate("login")}>Log in</span>
        </p>
      </div>
    </div>
  );
}
